      { body: "Screen Actors Guild Awards (26th)", category: "Outstanding Performance by a Male Actor in a Supporting Role (Joe Pesci)", result: "Nominated", year: 2020 },
      { body: "Critics\' Choice Movie Awards (25th)", category: "Best Picture", result: "Nominated", year: 2020 },
      { body: "Critics\' Choice Movie Awards (25th)", category: "Best Director (Martin Scorsese)", result: "Nominated", year: 2020 }
