      { body: "Academy Awards (76th)", category: "Best Cinematography", result: "Nominated", year: 2004 },
      { body: "Academy Awards (76th)", category: "Best Film Editing", result: "Nominated", year: 2004 },
      { body: "Academy Awards (76th)", category: "Best Adapted Screenplay", result: "Nominated", year: 2004 },
      { body: "BAFTA Film Awards (57th)", category: "Best Direction", result: "Nominated", year: 2004 },
      { body: "BAFTA Film Awards (57th)", category: "Best Cinematography", result: "Nominated", year: 2004 },
      { body: "Golden Globe Awards (61st)", category: "Best Foreign Language Film", result: "Nominated", year: 2004 },
      { body: "César Awards (29th)", category: "Best Foreign Film", result: "Nominated", year: 2004 },
      { body: "Independent Spirit Awards (19th)", category: "Best Foreign Film", result: "Nominated", year: 2004 }
