      { body: "Academy Awards (69th)", category: "Best Film Editing", result: "Nominated", year: 1997 },
      { body: "BAFTA Film Awards (50th)", category: "Best Original Screenplay", result: "Nominated", year: 1997 },
      { body: "BAFTA Film Awards (50th)", category: "Best Actress in a Leading Role", result: "Nominated", year: 1997 },
      { body: "Golden Globe Awards (54th)", category: "Best Motion Picture - Drama", result: "Nominated", year: 1997 },
      { body: "Golden Globe Awards (54th)", category: "Best Actress in a Motion Picture - Drama", result: "Nominated", year: 1997 },
      { body: "Screen Actors Guild Awards (3rd)", category: "Outstanding Performance by a Female Actor in a Leading Role", result: "Nominated", year: 1997 }
