      { body: "BAFTA Film Awards (44th)", category: "Best Adapted Screenplay", result: "Nominated", year: 1991 },
      { body: "Golden Globe Awards (48th)", category: "Best Motion Picture - Drama", result: "Nominated", year: 1991 },
      { body: "Golden Globe Awards (48th)", category: "Best Director", result: "Nominated", year: 1991 },
      { body: "Golden Globe Awards (48th)", category: "Best Supporting Actor", result: "Nominated", year: 1991 }
