      { body: "Los Angeles Film Critics Association Awards (2001)", category: "Best Film", result: "Won", year: 2001 },
      { body: "Los Angeles Film Critics Association Awards (2001)", category: "Best Cinematography", result: "Won", year: 2001 },
      { body: "Bodil Awards (45th)", category: "Best Non-American Film", result: "Won", year: 2002 },
      { body: "Cannes Film Festival (53rd)", category: "Palme d\'Or", result: "Nominated", year: 2000 },
      { body: "César Awards (27th)", category: "Best Foreign Film", result: "Nominated", year: 2002 },
      { body: "BAFTA Film Awards (55th)", category: "Best Film Not in the English Language", result: "Nominated", year: 2002 },
      { body: "Independent Spirit Awards (17th)", category: "Best Foreign Film", result: "Nominated", year: 2002 }
