      { body: "Hong Kong Film Awards (24th)", category: "Best Actor (Tony Leung Chiu-wai)", result: "Nominated", year: 2005 },
      { body: "Hong Kong Film Awards (24th)", category: "Best Actress (Zhang Ziyi)", result: "Nominated", year: 2005 },
      { body: "Cannes Film Festival (57th)", category: "Palme d\'Or", result: "Nominated", year: 2004 },
      { body: "BAFTA Film Awards (58th)", category: "Best Film Not in the English Language", result: "Nominated", year: 2005 },
      { body: "César Awards (50th)", category: "Best Foreign Film", result: "Nominated", year: 2005 }
