      { body: "Bodil Awards (2012)", category: "Best Supporting Actress", result: "Nominated", year: 2012 },
      { body: "Goya Awards (2012)", category: "Best European Film", result: "Nominated", year: 2012 },
      { body: "Independent Spirit Awards (2012)", category: "Best International Film", result: "Nominated", year: 2012 },
      { body: "Saturn Awards (38th)", category: "Best International Film", result: "Nominated", year: 2012 }
