      { body: "Seville European Film Festival (18th)", category: "Giraldillo de Oro for Best Film", result: "Nominated", year: 2021 },
      { body: "Ghent International Film Festival (48th)", category: "Grand Prix", result: "Nominated", year: 2021 },
      { body: "Jerusalem Film Festival (38th)", category: "Nechama Rivilin Award for Best International Film", result: "Nominated", year: 2021 },
      { body: "Palm Springs International Film Festival (33rd)", category: "Best Foreign Language Film", result: "Nominated", year: 2021 },
      { body: "Sydney Film Festival (68th)", category: "Best Film", result: "Nominated", year: 2021 },
      { body: "IndieWire Critics Poll", category: "Best Film", result: "Nominated", year: 2021 }
