      { body: "BAFTA Film Awards (72nd)", category: "Best Supporting Actress", result: "Nominated", year: 2019 },
      { body: "BAFTA Film Awards (72nd)", category: "Best Adapted Screenplay", result: "Nominated", year: 2019 },
      { body: "Golden Globe Awards (76th)", category: "Best Motion Picture – Drama", result: "Nominated", year: 2019 },
      { body: "Golden Globe Awards (76th)", category: "Best Supporting Actress – Motion Picture", result: "Nominated", year: 2019 },
      { body: "Screen Actors Guild Awards (25th)", category: "Outstanding Performance by a Female Actor in a Supporting Role", result: "Nominated", year: 2019 },
      { body: "Screen Actors Guild Awards (25th)", category: "Outstanding Performance by a Cast in a Motion Picture", result: "Nominated", year: 2019 }
