      { body: "BAFTA Film Awards (54th)", category: "Best Editing", result: "Nominated", year: 2001 },
      { body: "BAFTA Film Awards (54th)", category: "Best Costume Design", result: "Nominated", year: 2001 },
      { body: "BAFTA Film Awards (54th)", category: "Best Production Design", result: "Nominated", year: 2001 },
      { body: "BAFTA Film Awards (54th)", category: "Best Sound", result: "Nominated", year: 2001 },
      { body: "Golden Globe Awards (58th)", category: "Best Director", result: "Nominated", year: 2001 },
      { body: "Golden Globe Awards (58th)", category: "Best Original Score", result: "Nominated", year: 2001 }
