      { body: "Golden Globe Awards (60th)", category: "Best Actor in a Motion Picture - Drama", result: "Nominated", year: 2003 },
      { body: "Screen Actors Guild Awards (9th)", category: "Outstanding Performance by a Male Actor in a Leading Role", result: "Nominated", year: 2003 }
