      { actor: "Yuuki Masuda", role: "Hirota (voice)", photoUrl: "https://image.tmdb.org/t/p/w185/lD2tzzIa9BEmalAoHRBDb9Y4pSn.jpg" },
      { actor: "Ichiro Nagai", role: "Torahige (voice)", photoUrl: "https://image.tmdb.org/t/p/w185/d5LuqwoIjMIqKvKmEk5y6AZY1Ww.jpg" },
      { actor: "Yoshimasa Kondo", role: "Homeroom Teacher (voice)", photoUrl: "https://image.tmdb.org/t/p/w185/6WH3eIKWcAncSTJumXkkRgrAQjI.jpg" },
      { actor: "Issey Takahashi", role: "Classmate (voice)", photoUrl: "https://image.tmdb.org/t/p/w185/o5V869FSj4cCS0gnpHrlbX3xV9v.jpg" }
