      { body: "Goya Awards (21st)", category: "Best Original Screenplay", result: "Won", year: 2007 },
      { body: "European Film Awards (19th)", category: "Best Actress", result: "Won", year: 2006 },
      { body: "Screen Actors Guild Awards (13th)", category: "Outstanding Performance by a Female Actor in a Leading Role", result: "Nominated", year: 2007 },
      { body: "Academy Awards (79th)", category: "Best Actress in a Leading Role", result: "Nominated", year: 2007 },
      { body: "Academy Awards (79th)", category: "Best Original Screenplay", result: "Nominated", year: 2007 },
      { body: "BAFTA Film Awards (60th)", category: "Best Film Not in the English Language", result: "Nominated", year: 2007 },
      { body: "Golden Globe Awards (64th)", category: "Best Foreign Language Film", result: "Nominated", year: 2007 }
