      { body: "BAFTA Film Awards (61st)", category: "Best Adapted Screenplay", result: "Nominated", year: 2008 },
      { body: "BAFTA Film Awards (61st)", category: "Best Editing", result: "Nominated", year: 2008 },
      { body: "Golden Globe Awards (65th)", category: "Best Motion Picture – Drama", result: "Nominated", year: 2008 },
      { body: "Golden Globe Awards (65th)", category: "Best Director – Motion Picture", result: "Nominated", year: 2008 },
      { body: "Screen Actors Guild Awards (14th)", category: "Outstanding Cast in a Motion Picture", result: "Nominated", year: 2008 }
