      { body: "National Society of Film Critics Awards (2002)", category: "Best Screenplay", result: "Won", year: 2002 },
      { body: "Academy Awards (74th)", category: "Best Director", result: "Nominated", year: 2002 },
      { body: "Academy Awards (74th)", category: "Best Original Screenplay", result: "Nominated", year: 2002 },
      { body: "BAFTA Film Awards (55th)", category: "Best Editing", result: "Nominated", year: 2002 },
      { body: "WGA Awards (54th)", category: "Best Original Screenplay", result: "Nominated", year: 2002 },
      { body: "Independent Spirit Awards (17th)", category: "Best Cinematography", result: "Nominated", year: 2002 },
      { body: "Independent Spirit Awards (17th)", category: "Best Female Lead", result: "Nominated", year: 2002 }
