      { body: "Baeksang Arts Awards (40th)", category: "Best Film", result: "Won", year: 2004 },
      { body: "Baeksang Arts Awards (40th)", category: "Best Director", result: "Won", year: 2004 },
      { body: "Baeksang Arts Awards (40th)", category: "Best Actor", result: "Won", year: 2004 }
