      { body: "Los Angeles Film Critics Association Awards (2006)", category: "Best Director", result: "Won", year: 2006 },
      { body: "Los Angeles Film Critics Association Awards (2006)", category: "Best Cinematography", result: "Won", year: 2006 },
      { body: "National Society of Film Critics Awards (2007)", category: "Best Film", result: "Won", year: 2007 },
      { body: "National Society of Film Critics Awards (2007)", category: "Best Cinematography", result: "Won", year: 2007 },
      { body: "Academy Awards (79th)", category: "Best Cinematography", result: "Nominated", year: 2007 },
      { body: "Academy Awards (79th)", category: "Best Film Editing", result: "Nominated", year: 2007 },
      { body: "Academy Awards (79th)", category: "Best Adapted Screenplay", result: "Nominated", year: 2007 },
      { body: "BAFTA Film Awards (60th)", category: "Best Adapted Screenplay", result: "Nominated", year: 2007 },
      { body: "BAFTA Film Awards (60th)", category: "Best Cinematography", result: "Nominated", year: 2007 },
      { body: "BAFTA Film Awards (60th)", category: "Best Editing", result: "Nominated", year: 2007 },
      { body: "Writers Guild of America Awards (59th)", category: "Best Adapted Screenplay", result: "Nominated", year: 2007 }
