      { body: "Academy Awards (87th)", category: "Best Picture", result: "Nominated", year: 2015 },
      { body: "Academy Awards (87th)", category: "Best Adapted Screenplay", result: "Nominated", year: 2015 },
      { body: "BAFTA Film Awards (68th)", category: "Best Editing", result: "Nominated", year: 2015 },
      { body: "BAFTA Film Awards (68th)", category: "Best Sound", result: "Nominated", year: 2015 },
      { body: "Golden Globe Awards (72nd)", category: "Best Motion Picture - Drama", result: "Nominated", year: 2015 },
      { body: "Directors Guild of America Awards (67th)", category: "Outstanding Directorial Achievement in Feature Film", result: "Nominated", year: 2015 },
      { body: "Writers Guild of America Awards (67th)", category: "Best Adapted Screenplay", result: "Nominated", year: 2015 }
