      { body: "Golden Globe Awards (73rd)", category: "Best Motion Picture, Drama", result: "Nominated", year: 2016 },
      { body: "Golden Globe Awards (73rd)", category: "Best Director", result: "Nominated", year: 2016 },
      { body: "Golden Globe Awards (73rd)", category: "Best Screenplay", result: "Nominated", year: 2016 },
      { body: "Screen Actors Guild Awards (22nd)", category: "Outstanding Performance by a Cast in a Motion Picture", result: "Nominated", year: 2016 },
      { body: "Screen Actors Guild Awards (22nd)", category: "Outstanding Performance by a Male Actor in a Supporting Role", result: "Nominated", year: 2016 },
      { body: "Directors Guild of America Awards (68th)", category: "Outstanding Directorial Achievement in Motion Pictures", result: "Nominated", year: 2016 }
