      { body: "BAFTA Film Awards (67th)", category: "Best Cinematography", result: "Nominated", year: 2014 },
      { body: "BAFTA Film Awards (67th)", category: "Best Editing", result: "Nominated", year: 2014 },
      { body: "Golden Globe Awards (71st)", category: "Best Motion Picture - Drama", result: "Nominated", year: 2014 },
      { body: "Golden Globe Awards (71st)", category: "Best Director - Motion Picture", result: "Nominated", year: 2014 },
      { body: "Golden Globe Awards (71st)", category: "Best Actress in a Motion Picture - Drama", result: "Nominated", year: 2014 }
